class Solution {
public:
    int countVowelPermutation(int n) {
        const int MOD = 1e9 + 7;
        long long dp[5] = {1, 1, 1, 1, 1};
        for (int i = 2; i <= n; i++) {
            long long next[5] = {0};
            next[0] = (dp[1] + dp[2] + dp[4]) % MOD;
            next[1] = (dp[0] + dp[2]) % MOD;
            next[2] = (dp[0] + dp[1] + dp[3]) % MOD;
            next[3] = (dp[2]) % MOD;
            next[4] = (dp[2] + dp[3]) % MOD;
            for (int j = 0; j < 5; j++) {
                dp[j] = next[j];
            }
        }
        return (dp[0] + dp[1] + dp[2] + dp[3] + dp[4]) % MOD;
    }
};

